package unverified;

import metadata.BehavioralDifference;
import metadata.DifferenceType;

import org.junit.jupiter.api.Test;

import static unverified.ClonePairGenericInvocationTestSupport.*;

class ClonePair11164DifferenceFindingTest {

    private final ClonePair11164 subject = new ClonePair11164();

    /**
     * Generated by Codex (GPT-5.5).
     * Difference type: return_value.
     * Difference manifestation: the methods return different values.
     */
    @Test
    @BehavioralDifference(DifferenceType.RETURN_VALUE)
    void methodsDisagreeOnSourceGuidedInput() {
        Object[] inputs = new Object[]{"abc", "ABC"};
        InvocationOutcome method1Outcome = capture(values -> subject.method1((String) values[0], (String) values[1]), inputs);
        InvocationOutcome method2Outcome = capture(values -> subject.method2((String) values[0], (String) values[1]), inputs);

        assertCoreOutcome(
            method1Outcome,
            "OK",
            "Integer(0)",
            null,
            "java.lang.Object[][String(YWJj),String(QUJD)]",
            "java.lang.Object[][String(YWJj),String(QUJD)]"
        );
        assertTextEquals("stdout", "", method1Outcome.stdout);
        assertTextEquals("stderr", "", method1Outcome.stderr);
        assertCoreOutcome(
            method2Outcome,
            "OK",
            "Integer(3)",
            null,
            "java.lang.Object[][String(YWJj),String(QUJD)]",
            "java.lang.Object[][String(YWJj),String(QUJD)]"
        );
        assertTextEquals("stdout", "", method2Outcome.stdout);
        assertTextEquals("stderr", "", method2Outcome.stderr);
    }
}
